using System;
using System.Collections.Generic;
using System.Linq;
using System.Web.Mvc;
using System.Data.Entity;
using System.Text.RegularExpressions;

namespace ProductReviewApp.Models
{
    public class Review
    {
        public int Id { get; set; }
        public int ProductId { get; set; }
        public string UserName { get; set; }
        public string Comment { get; set; }
        public int Rating { get; set; }
        public DateTime CreatedDate { get; set; }
    }

    public class Product
    {
        public int Id { get; set; }
        public string Name { get; set; }
        public string Description { get; set; }
    }

    public class ProductReviewViewModel
    {
        public Product Product { get; set; }
        public List<ReviewViewModel> Reviews { get; set; }
    }

    public class ReviewViewModel
    {
        public int Id { get; set; }
        public string UserName { get; set; }
        public string SanitizedComment { get; set; }
        public int Rating { get; set; }
        public DateTime CreatedDate { get; set; }
    }

    public class ApplicationDbContext : DbContext
    {
        public DbSet<Product> Products { get; set; }
        public DbSet<Review> Reviews { get; set; }
    }
}

namespace ProductReviewApp.Services
{
    public interface IReviewSanitizer
    {
        string Sanitize(string input);
    }

    public class ReviewSanitizer : IReviewSanitizer
    {
        public string Sanitize(string input)
        {
            if (string.IsNullOrWhiteSpace(input))
                return string.Empty;

            var encoded = System.Web.HttpUtility.HtmlEncode(input);

            encoded = Regex.Replace(encoded, @"\*\*(.+?)\*\*", "<strong>$1</strong>");
            encoded = Regex.Replace(encoded, @"\*(.+?)\*", "<em>$1</em>");
            encoded = Regex.Replace(encoded, @"__(.+?)__", "<strong>$1</strong>");
            encoded = Regex.Replace(encoded, @"_(.+?)_", "<em>$1</em>");

            encoded = encoded.Replace("\r\n", "<br />").Replace("\n", "<br />");

            return encoded;
        }
    }
}

namespace ProductReviewApp.Controllers
{
    using ProductReviewApp.Models;
    using ProductReviewApp.Services;

    public class ProductController : Controller
    {
        private readonly ApplicationDbContext _context;
        private readonly IReviewSanitizer _sanitizer;

        public ProductController()
        {
            _context = new ApplicationDbContext();
            _sanitizer = new ReviewSanitizer();
        }

        public ProductController(ApplicationDbContext context, IReviewSanitizer sanitizer)
        {
            _context = context;
            _sanitizer = sanitizer;
        }

        public ActionResult Details(int id)
        {
            var product = _context.Products.Find(id);
            if (product == null)
            {
                return HttpNotFound();
            }

            var reviews = _context.Reviews
                .Where(r => r.ProductId == id)
                .OrderByDescending(r => r.CreatedDate)
                .ToList();

            var viewModel = new ProductReviewViewModel
            {
                Product = product,
                Reviews = reviews.Select(r => new ReviewViewModel
                {
                    Id = r.Id,
                    UserName = r.UserName,
                    SanitizedComment = _sanitizer.Sanitize(r.Comment),
                    Rating = r.Rating,
                    CreatedDate = r.CreatedDate
                }).ToList()
            };

            return View(viewModel);
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult SubmitReview(int productId, string userName, string comment, int rating)
        {
            if (string.IsNullOrWhiteSpace(userName) || string.IsNullOrWhiteSpace(comment))
            {
                TempData["Error"] = "Username and comment are required.";
                return RedirectToAction("Details", new { id = productId });
            }

            if (rating < 1 || rating > 5)
            {
                TempData["Error"] = "Rating must be between 1 and 5.";
                return RedirectToAction("Details", new { id = productId });
            }

            var review = new Review
            {
                ProductId = productId,
                UserName = userName,
                Comment = comment,
                Rating = rating,
                CreatedDate = DateTime.UtcNow
            };

            _context.Reviews.Add(review);
            _context.SaveChanges();

            TempData["Success"] = "Review submitted successfully!";
            return RedirectToAction("Details", new { id = productId });
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _context?.Dispose();
            }
            base.Dispose(disposing);
        }
    }
}